using namespace std;

class UnionFind {
private:
    vector<int> parent;
    vector<int> rank;
    int components;

public:
    UnionFind(int n) : parent(n), rank(n, 0), components(n) {
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
        }
    }

    int find(int u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    bool unite(int u, int v) {
        int rootU = find(u);
        int rootV = find(v);
        if (rootU == rootV) {
            return false;
        }
        if (rank[rootU] > rank[rootV]) {
            parent[rootV] = rootU;
        } else if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV;
        } else {
            parent[rootV] = rootU;
            rank[rootU]++;
        }
        components--;
        return true;
    }

    int getComponents() const {
        return components;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    long long left = 0;
    long long right = 1e6;
    long long answer = right;

    while (left <= right) {
        long long mid = left + (right - left) / 2;
        UnionFind uf(n);
        for (const auto& edge : edges) {
            if (edge[2] > mid) {
                continue;
            }
            uf.unite(edge[0], edge[1]);
        }
        if (uf.getComponents() <= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}

